import anthropic
import json

client = anthropic.Anthropic()

def spawn_sub_agent(
    task: str,
    scoped_context: list[dict],
    tools: list[dict] | None = None,
) -> str:
    """
    Spawn a sub-agent with a clean, task-scoped context.
    Only the information relevant to the sub-task is included —
    the parent's full conversation history is intentionally excluded.
    """
    messages = scoped_context + [{"role": "user", "content": task}]
    kwargs = {"model": "claude-opus-4-8", "max_tokens": 2048, "messages": messages}
    if tools:
        kwargs["tools"] = tools
    response = client.messages.create(**kwargs)
    # Return the text summary only — not the full response object
    for block in response.content:
        if block.type == "text":
            return block.text
    return ""


# Parent agent has full context; sub-agent only sees the slice it needs
search_result = spawn_sub_agent(
    task="Search for the three most recent papers on RAG evaluation benchmarks.",
    scoped_context=[
        {"role": "user", "content": "You are a search specialist. Use only the provided tools."}
    ],
    tools=[{"name": "web_search", "description": "Search the web", "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}}],
)

analysis_result = spawn_sub_agent(
    task="Identify key metrics from the following search results.",
    scoped_context=[
        {"role": "user", "content": f"Raw search results:\n{search_result}"}
    ],
)

# Parent merges summaries — sub-agent history never re-enters parent context
final_context = f"Search summary:\n{search_result}\n\nAnalysis:\n{analysis_result}"
print(final_context[:500])

import asyncio
import anthropic

client = anthropic.Anthropic()


async def spawn_sub_agent_async(
    task: str,
    scoped_context: list[dict],
) -> str:
    """Async wrapper so multiple sub-agents run concurrently."""
    loop = asyncio.get_event_loop()
    return await loop.run_in_executor(
        None,
        lambda: _call_sync(task, scoped_context),
    )


def _call_sync(task: str, scoped_context: list[dict]) -> str:
    messages = scoped_context + [{"role": "user", "content": task}]
    response = client.messages.create(
        model="claude-opus-4-8",
        max_tokens=1024,
        messages=messages,
    )
    for block in response.content:
        if block.type == "text":
            return block.text
    return ""


async def orchestrate(tasks: list[dict]) -> list[str]:
    """
    Dispatch all sub-agents concurrently.
    Each gets its own isolated context — no shared mutable state.
    """
    coros = [
        spawn_sub_agent_async(t["task"], t["context"])
        for t in tasks
    ]
    results = await asyncio.gather(*coros)
    return list(results)


tasks = [
    {
        "task": "Summarise the pricing model for product A.",
        "context": [{"role": "user", "content": "You are a pricing analyst. Data: product_A_pricing.csv"}],
    },
    {
        "task": "Identify legal risks in the draft contract.",
        "context": [{"role": "user", "content": "You are a legal reviewer. Draft: contract_v2.txt"}],
    },
    {
        "task": "Translate the executive summary to French.",
        "context": [{"role": "user", "content": "You are a professional translator."}],
    },
]

results = asyncio.run(orchestrate(tasks))
for i, r in enumerate(results):
    print(f"Sub-agent {i+1}: {r[:120]}")
